  rc_orders = EXCLUDED.rc_orders, rc_revenue = EXCLUDED.rc_revenue,
  gross_sales = EXCLUDED.gross_sales, discounts = EXCLUDED.discounts,
  refunds = EXCLUDED.refunds, taxes = EXCLUDED.taxes, shipping = EXCLUDED.shipping,
  synced_at = now();
